package form;
import controller.*;import model.*;import util.UIUtils;import javax.swing.*;import javax.swing.table.DefaultTableModel;import java.awt.*;
public class PengaturanForm extends JPanel{PengaturanController c=new PengaturanController();AuthController auth=new AuthController();public PengaturanForm(User u){setLayout(new BorderLayout());JPanel p=UIUtils.page("Pengaturan & Keamanan");JTabbedPane tabs=new JTabbedPane();tabs.addTab("Role Management",tablePanel(new String[]{"ID","Nama","Username","Role","Created"},()->c.users()));tabs.addTab("Audit Log",tablePanel(new String[]{"Waktu","User","Aksi","Target","Data Lama","Data Baru"},()->c.auditLog()));tabs.addTab("Profil Sekolah",profil());tabs.addTab("Ganti Password",password(u));p.add(tabs);add(p);}interface Loader{java.util.List<Object[]> load()throws Exception;}JPanel tablePanel(String[] cols,Loader l){JPanel p=new JPanel(new BorderLayout());DefaultTableModel m=new DefaultTableModel(cols,0);try{for(Object[] r:l.load())m.addRow(r);}catch(Exception ignored){}p.add(UIUtils.tableScroll(new JTable(m)));return p;}JPanel profil(){JPanel p=new JPanel(new GridLayout(0,2,8,8));JTextField nama=UIUtils.textField(20),alamat=UIUtils.textField(20),tel=UIUtils.textField(12),email=UIUtils.textField(16),kep=UIUtils.textField(16),ben=UIUtils.textField(16),logo=UIUtils.textField(16);Pengaturan pg;try{pg=c.get();nama.setText(pg.getNamaSekolah());alamat.setText(pg.getAlamat());tel.setText(pg.getTelepon());email.setText(pg.getEmail());kep.setText(pg.getKepalaSekolah());ben.setText(pg.getBendahara());logo.setText(pg.getLogoPath());}catch(Exception ignored){pg=new Pengaturan();}Pengaturan finalPg=pg;p.add(UIUtils.formLabel("Nama Institusi"));p.add(nama);p.add(UIUtils.formLabel("Alamat"));p.add(alamat);p.add(UIUtils.formLabel("Telepon"));p.add(tel);p.add(UIUtils.formLabel("Email"));p.add(email);p.add(UIUtils.formLabel("Kepala Sekolah"));p.add(kep);p.add(UIUtils.formLabel("Bendahara"));p.add(ben);p.add(UIUtils.formLabel("Logo Path"));p.add(logo);JButton sim=UIUtils.button("Simpan Profil",UIUtils.BLUE);sim.addActionListener(e->{try{c.simpan(new Pengaturan(finalPg.getId(),nama.getText(),alamat.getText(),tel.getText(),email.getText(),kep.getText(),ben.getText(),logo.getText()));JOptionPane.showMessageDialog(this,"Tersimpan");}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});p.add(new JLabel());p.add(sim);return p;}JPanel password(User u){JPanel p=new JPanel(new FlowLayout(FlowLayout.LEFT));JPasswordField pass=new JPasswordField(18);JButton b=UIUtils.button("Ganti Password",UIUtils.RED);b.addActionListener(e->{try{auth.gantiPassword(u.getId(),new String(pass.getPassword()));JOptionPane.showMessageDialog(this,"Password diganti");}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});p.add(UIUtils.formLabel("Password Baru"));p.add(pass);p.add(b);return p;}}
